import { GoogleMap, LoadScript } from '@react-google-maps/api';

const mapContainerStyle = {
  width: '100vw',
  height: '100vh'
};

const center = {
  lat: 37.7749,
  lng: -122.4194
};

function App() {
  return (
    <LoadScript googleMapsApiKey="AIzaSyBGNDvvjBWtpAWZXtTnTEWgJ0sYigcrW0g"

    >
      <GoogleMap
        mapContainerStyle={mapContainerStyle}
        center={center}
        zoom={13}
        mapTypeId="hybrid"
      >
      </GoogleMap>
    </LoadScript>
  );
}

export default App;
